import{_ as e,o as l,c as i,a3 as r}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"API 配置（移动端）","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/mobile/llm-api.md","filePath":"user-guide/mobile/llm-api.md","lastUpdated":1781934556000}'),t={name:"user-guide/mobile/llm-api.md"};function o(h,a,d,n,s,p){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="api-配置-移动端" tabindex="-1">API 配置（移动端） <a class="header-anchor" href="#api-配置-移动端" aria-label="Permalink to &quot;API 配置（移动端）&quot;">​</a></h1><p>移动端的「LLM 服务」用于管理 AI 服务渠道、模型和 API Key。它是移动端 LLM 对话能否正常发送请求的前置配置。</p><h2 id="打开配置页" tabindex="-1">打开配置页 <a class="header-anchor" href="#打开配置页" aria-label="Permalink to &quot;打开配置页&quot;">​</a></h2><ol><li>在移动端首页点击「LLM 服务」。</li><li>如果还没有渠道，页面会显示空状态。</li><li>点击右上角加号。</li><li>选择一个预设服务商，或创建自定义渠道。</li></ol><h2 id="新建渠道" tabindex="-1">新建渠道 <a class="header-anchor" href="#新建渠道" aria-label="Permalink to &quot;新建渠道&quot;">​</a></h2><p>选择预设后，系统会带入服务商名称、接口类型、默认 Base URL 和部分默认模型。你需要补充：</p><ul><li>API Key。</li><li>需要使用的模型。</li><li>是否启用该渠道。</li><li>如有需要，配置自定义请求头和端点。</li></ul><p>如果你的服务商兼容 OpenAI 格式，可以选择 OpenAI 兼容类型，并填写服务商提供的 Base URL。</p><h2 id="编辑渠道" tabindex="-1">编辑渠道 <a class="header-anchor" href="#编辑渠道" aria-label="Permalink to &quot;编辑渠道&quot;">​</a></h2><p>点击渠道卡片进入编辑弹层。常用操作包括：</p><ul><li>修改渠道名称。</li><li>启用或禁用渠道。</li><li>增删 API Key。</li><li>管理模型列表。</li><li>设置图标。</li><li>配置自定义 Header。</li><li>配置自定义 Endpoint。</li></ul><p>保存后，LLM 对话会读取已启用渠道和模型。</p><h2 id="管理模型" tabindex="-1">管理模型 <a class="header-anchor" href="#管理模型" aria-label="Permalink to &quot;管理模型&quot;">​</a></h2><p>模型列表决定聊天页可选的模型名称。你可以：</p><ul><li>使用预设模型。</li><li>手动新增模型名称。</li><li>通过模型获取功能从服务商接口拉取。</li><li>编辑模型能力元数据。</li></ul><p>如果服务商不提供模型列表接口，手动添加模型即可。</p><h2 id="key-管理" tabindex="-1">Key 管理 <a class="header-anchor" href="#key-管理" aria-label="Permalink to &quot;Key 管理&quot;">​</a></h2><p>每个渠道可以保存一个或多个 API Key。使用建议：</p><ul><li>不要把同一个 Key 写到多个不需要的渠道里。</li><li>失效 Key 及时删除。</li><li>如果服务商限制频率，可以准备多个 Key 并按渠道策略管理。</li><li>不要把真实 Key 填入截图或公开 issue。</li></ul><h2 id="自定义端点" tabindex="-1">自定义端点 <a class="header-anchor" href="#自定义端点" aria-label="Permalink to &quot;自定义端点&quot;">​</a></h2><p>自定义端点用于适配不同服务商的路径差异，例如聊天、模型列表或媒体能力接口。移动端会尽量复用桌面端 LLM API 的核心请求构建逻辑。</p><p>不确定时，先保持默认端点，只改 Base URL 和 API Key。</p><h2 id="排查请求失败" tabindex="-1">排查请求失败 <a class="header-anchor" href="#排查请求失败" aria-label="Permalink to &quot;排查请求失败&quot;">​</a></h2><ol><li>确认渠道已启用。</li><li>确认 API Key 不为空。</li><li>确认模型名与服务商文档一致。</li><li>确认 Base URL 没有重复路径，例如不要把 <code>/v1</code> 写两遍。</li><li>打开日志管理器，搜索渠道名称或错误状态码。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么添加渠道后聊天页仍然没有模型" tabindex="-1">为什么添加渠道后聊天页仍然没有模型？ <a class="header-anchor" href="#为什么添加渠道后聊天页仍然没有模型" aria-label="Permalink to &quot;为什么添加渠道后聊天页仍然没有模型？&quot;">​</a></h3><p>检查渠道是否启用，以及模型列表是否为空。部分预设不会自动带入所有模型，需要手动添加。</p><h3 id="base-url-应该填到哪里" tabindex="-1">Base URL 应该填到哪里？ <a class="header-anchor" href="#base-url-应该填到哪里" aria-label="Permalink to &quot;Base URL 应该填到哪里？&quot;">​</a></h3><p>填服务商 API 根地址。OpenAI 兼容服务通常类似 <code>https://example.com/v1</code>。如果请求日志显示路径重复，删掉多余的一段。</p><h3 id="支持多个服务商吗" tabindex="-1">支持多个服务商吗？ <a class="header-anchor" href="#支持多个服务商吗" aria-label="Permalink to &quot;支持多个服务商吗？&quot;">​</a></h3><p>支持。你可以创建多个渠道，并在聊天设置或模型选择器中切换。</p><h3 id="移动端配置和桌面端配置是否共用" tabindex="-1">移动端配置和桌面端配置是否共用？ <a class="header-anchor" href="#移动端配置和桌面端配置是否共用" aria-label="Permalink to &quot;移动端配置和桌面端配置是否共用？&quot;">​</a></h3><p>当前按移动端本地配置理解。跨端迁移或同步请以未来导入导出功能说明为准。</p>',33)])])}const b=e(t,[["render",o]]);export{c as __pageData,b as default};
